import { useEffect, useState } from "react";
import { getUsers } from "../../api/adminApi";

export default function UsersPage() {

  const [users, setUsers] = useState([]);

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = async () => {
    const data = await getUsers();
    setUsers(data.content);
  };

  return (
    <div>

      <h2>Пользователи</h2>

      <table>

        <thead>
          <tr>
            <th>ID</th>
            <th>Email</th>
            <th>Имя</th>
            <th>Роль</th>
            <th>Статус</th>
          </tr>
        </thead>

        <tbody>

          {users.map((u) => (
            <tr key={u.id}>
              <td>{u.id}</td>
              <td>{u.email}</td>
              <td>{u.fullName}</td>
              <td>{u.role}</td>
              <td>{u.status}</td>
            </tr>
          ))}

        </tbody>

      </table>

    </div>
  );
}
